} catch (e) { ok = false; }
const completedOk = resp.status === 'completed';
const inputHash = require('crypto').createHash('sha256').update(String((ctx.documents || '').length)).digest('hex');
return [{ json: { ...ctx, __sizer_valid: ok && completedOk, sizer_parsed: data, sizer_raw_text: rawText, sizer_raw_response: resp, sizer_input_hash: inputHash } }];

