const CAGR_BAND = Object.freeze({
  PASS_MIN: 15,               // >= 15% -> PASS
  WATCH_MIN: 5,                // [5%, 15%) -> WATCH; below -> FAIL
});

// ============================================================================
// §6.2 -- venture-scale ceiling.
// ============================================================================

const EXIT_MULTIPLE = 5;

// buyer_concentration -> share_assumption (Pear VC's 5x relative spread,
