const SHARE_BY_CONCENTRATION = Object.freeze({
  concentrated: 0.020,
  mid_market: 0.010,
  long_tail: 0.004,
});

// buyer_count -> buyer_concentration, the AUTHORITATIVE derivation (§6.2) --
