  BULLISH_MIN: 70,
  NEUTRAL_MIN: 40,
  // < NEUTRAL_MIN -> 'bear'; tamBand === 'UNKNOWN' -> 'undetermined' (never 'neutral')
});

// ============================================================================
// §6.4 -- idea_vs_market axis value = clamp(0, 100, sum of terms below).
// The moat bonus's +8-not-+10 case at threat_level=1 AND switching_cost=1 is
// the documented nonlinearity that holds the reachable maximum at exactly 100
// (50+20+15+8+7) instead of the raw sum's 102 -- do not collapse to a flat +10.
// ============================================================================

const IDEA_VS_MARKET_BASE = 50;

const IDEA_VS_MARKET_TERMS = Object.freeze({
  // keys are switching_cost values (1|2|3); `null` is the unknown/not-assessed state
  switchingCost: Object.freeze({ 1: 20, 2: 0, 3: -15, null: 0 }),
  // keys are threat_level values (1|2|3|4); `null` is the unknown/not-assessed state
  threatLevel: Object.freeze({ 1: 15, 2: 8, 3: 0, 4: -20, null: 0 }),
  moatBonus: 10,          // articulated accumulating advantage w/ public evidence, normal case
  moatBonusAtMax: 8,      // same, but threat_level=1 AND switching_cost=1 (the +8 nonlinearity)
  statusQuoDisplacedBonus: 7,
  zeroCompetitorsNamedPenalty: -10,
});

const IDEA_VS_MARKET_RANGE = Object.freeze({ MIN: 0, MAX: 100 }); // clamp bounds; realised range is 5..100 (§6.4)

// ============================================================================
// §6.6 -- founder axis value = clamp(0, 100, base + fmf + maturity), where
// base = latest scores.value WHERE axis='founder_score' (feature 03's
// persistent, person-scoped score -- an INPUT here, never copied/replaced).
// No such row -> founderAxisScore() returns null, not 0: a person 03 has not
// scored gets no founder axis row written at all.
// ============================================================================

const FOUNDER_AXIS_TERMS = Object.freeze({
  // founder-market fit (SIG-026): domain expertise vs. the resolved category.
  // keys: 'direct' | 'adjacent'; `null` is "not established"
  fmf: Object.freeze({ direct: 10, adjacent: 5, null: 0 }),
  // competitor-knowledge maturity (SIG-024), reusing §8's mismatch severity.
  // keys: 'material' | 'moderate' | 'minor' (a real assessed reading of low
  // severity) | 'no_mismatch_3plus_named' (no mismatch AND founder named >=3
  // competitors); `null` is "not assessable" (no deck / no founder
  // competition view) -- distinct from 'minor', both contribute 0 but for
  // different reasons (§6.0 vs. a genuine low-severity reading).
  maturity: Object.freeze({ material: -10, moderate: -5, minor: 0, no_mismatch_3plus_named: 5, null: 0 }),
});

const FOUNDER_AXIS_RANGE = Object.freeze({ MIN: 0, MAX: 100 });

// ============================================================================
// §6.5 -- confidence formula + hard caps (order: caps first, §7 penalty second).
// ============================================================================

const CONFIDENCE_FORMULA = Object.freeze({
  MISSING_COUNT_CAP: 5,
  EVIDENCE_CT_CAP: 6,
  MISSING_COUNT_STEP: 0.2,     // completeness = 1 - min(1, missing_count * 0.2)
  EVIDENCE_WEIGHT: 0.55,       // confidence = evidence_ct/6 * 0.55 + completeness * 0.45
  COMPLETENESS_WEIGHT: 0.45,
});

const CONFIDENCE_CAPS = Object.freeze({
  ZERO_EVIDENCE: 0.15,          // evidence_ct = 0
  NO_DOCUMENTED_EVIDENCE: 0.40, // no documented-tier evidence behind the size claim
  FEW_INDEPENDENT_DOMAINS: 0.55, // fewer than 2 independent registrable domains
  TOP_DOWN_ONLY: 0.45,          // top-down-only sizing (§6.1)
});

// §7 underestimation guard: -0.15 penalty applied AFTER all §6.5 hard caps,
// floored at 0.1 (never at 0 -- a fired guard still leaves a nonzero reading).
const SHADOW_MARKET_GUARD = Object.freeze({
  CONFIDENCE_PENALTY: 0.15,
  CONFIDENCE_FLOOR: 0.1,
});

// ============================================================================
// §4 -- curator + Tavily budget.
// ============================================================================

const CURATE = Object.freeze({
  RELEVANCE_MIN: 0.4,   // score >= 0.4 gate; first-party docs bypass this gate only
  TOP_N: 8,              // top-8 survivors per curated bucket
});

const TAVILY_BUDGET = Object.freeze({
  SEARCH_QUERIES_PER_CARD: 5,   // Q1-Q5, 1 credit each (basic)
  EXTRACT_MAX_URLS: 20,          // single batched /extract call, urls[] <= 20
  CREDIT_CAP_PER_CARD: 25,       // hard stop (config); expected cost is 9-14
});

// lib/f04/scoring.js
//
// Deterministic scoring core for feature 04 (market / idea_vs_market screening
// axes). Pure functions only -- no I/O, no n8n imports, no network. This is the
// module the plan calls "the deterministic scoring core built first": every
// number is unit-tested here before it is pasted verbatim into an n8n Code
// node (docs/backlog/04-market-trend-competition/plan.md, "Guiding decision").
//
// Authoritative source for every formula: docs/backlog/04-market-trend-competition/
// design.md rev.3, sections cited inline next to each function. All tunable
// numbers live in ./config.js -- nothing here hardcodes a threshold, weight or
// domain list.

const crypto = require('crypto');


// ============================================================================
// Small shared helpers
// ============================================================================

function clamp(min, max, value) {
  return Math.min(max, Math.max(min, value));
}

function isFiniteNumber(value) {
  return typeof value === 'number' && Number.isFinite(value);
}

// Looks up a term value in a `{1: x, 2: y, null: z}`-shaped table (§6.4-style
// per-state score tables). `key === null || key === undefined` maps to the
// table's `null` entry (the unknown/not-assessed state); any other key not
// present in the table is a programming error, not a silent 0 -- it throws,
// so a typo'd state string fails loudly instead of quietly scoring as unknown.
function scoreTermFor(table, key, label) {
  if (key === null || key === undefined) return table.null;
  if (!Object.prototype.hasOwnProperty.call(table, key)) {
    throw new Error(`scoring.js: unrecognized ${label} state: ${JSON.stringify(key)}`);
  }
  return table[key];
}

// ============================================================================
// §6.1 -- vc_rule_check (half-open intervals, applied to tam_low / cagr_pct_low)
// ============================================================================

function tamBand(tamLow) {
  if (!isFiniteNumber(tamLow)) return 'UNKNOWN';
  if (tamLow >= TAM_BAND.PASS_MIN) return 'PASS';
  if (tamLow >= TAM_BAND.WATCH_MIN) return 'WATCH';
  return 'FAIL';
}

function cagrBand(cagrPct) {
  if (!isFiniteNumber(cagrPct)) return 'UNKNOWN';
  if (cagrPct >= CAGR_BAND.PASS_MIN) return 'PASS';
  if (cagrPct >= CAGR_BAND.WATCH_MIN) return 'WATCH';
  return 'FAIL';
}

// ============================================================================
// §6.2 -- venture-scale ceiling
// ============================================================================

// buyer_count -> buyer_concentration. THE authoritative derivation -- the
// market-categorizer's pre-search guess is a query hint only (§6.2 CR-4) and
// is overridden by this whenever the two disagree.
function deriveConcentration(buyerCount) {
  if (!isFiniteNumber(buyerCount) || buyerCount < 0) return 'unknown';
  if (buyerCount < BUYER_CONCENTRATION_THRESHOLDS.concentratedMax) return 'concentrated';
  if (buyerCount <= BUYER_CONCENTRATION_THRESHOLDS.midMarketMax) return 'mid_market';
  return 'long_tail';
}

function impliedExitBand(impliedExit) {
  if (!isFiniteNumber(impliedExit)) return 'UNKNOWN';
  if (impliedExit >= IMPLIED_EXIT_BAND.PASS_MIN) return 'PASS';
  if (impliedExit >= IMPLIED_EXIT_BAND.WATCH_MIN) return 'WATCH';
  return 'FAIL';
}

// NOTE on a design.md §6.2 self-contradiction this function deliberately does
// NOT reproduce (reported to the team lead, not silently resolved):
//
// §6.2's breakpoint table labels a "factor" column (0.50 / 0.25 / 0.10 for
// concentrated/mid_market/long_tail) and uses it in two prose worked examples
// ("$250M implied exit" for mid_market at $1B TAM; "$150M implied" for
// concentrated at $300M TAM). Both are arithmetically inconsistent with
// design.md's own share_assumption table (0.020/0.010/0.004) times the stated
// exit_multiple (5) -- that product is 0.10/0.05/0.02, a flat 5x below the
// table's "factor" column. The CORRECT product (share_assumption *
// exit_multiple) is also what design.md's own sentence for the concentrated
// tier states explicitly ("0.020 x 5 = 0.10 and $100M / 0.10 = $1B"), and it
// is the only formula that reproduces the FAIL/WATCH/PASS tam_low breakpoints
// design.md itself publishes (300M/1B, 600M/2B, 1.5B/5B -- ratio exactly 0.30
// in every tier). This function implements implied_exit = tam_used *
// share_assumption * exit_multiple, banded against IMPLIED_EXIT_BAND, which
// matches the breakpoint table and the required acceptance grid; the
// "factor" column and the two dollar-figure prose examples do not match
// their own document and should be corrected in design.md rev.4.
function ventureScaleCheck(tamLow, concentration) {
  const tamKnown = isFiniteNumber(tamLow);
  const concentrationKnown = Object.prototype.hasOwnProperty.call(SHARE_BY_CONCENTRATION, concentration);

  // The two founder-standard comparison scenarios (§6.2: "the investor sees
  // what the founder's own assumption would imply") are independent of
  // buyer_concentration, so they are computed whenever tam_low is known --
  // even when concentration itself is not, which is exactly when a reader
  // most needs a sanity-check reference point.
  const scenarios = [];
  if (tamKnown) {
    for (const share of FOUNDER_STANDARD_SHARE_SCENARIOS) {
      scenarios.push({
        label: `founder_${Math.round(share * 100)}pct`,
        share,
        implied_exit: tamLow * share * EXIT_MULTIPLE,
      });
    }
  }

  if (!tamKnown || !concentrationKnown) {
    return {
      status: 'UNKNOWN',
      tam_used: tamKnown ? tamLow : null,
      share_assumption: null,
      share_rationale: null,
      exit_multiple: EXIT_MULTIPLE,
      implied_exit_value: null,
      scenarios,
      rationale: !tamKnown
        ? 'no TAM established -- venture-scale ceiling not computed (§6.2)'
        : 'buyer_concentration not established -- venture-scale ceiling not computed (§6.2)',
    };
  }

  const share = SHARE_BY_CONCENTRATION[concentration];
  const impliedExit = tamLow * share * EXIT_MULTIPLE;
  const status = impliedExitBand(impliedExit);

  scenarios.unshift({ label: 'share_assumption', share, implied_exit: impliedExit });

  return {
    status,
    tam_used: tamLow,
    share_assumption: share,
    share_rationale: `${concentration} buyer base -> calibrated share ${(share * 100).toFixed(1)}% (§6.2)`,
    exit_multiple: EXIT_MULTIPLE,
    implied_exit_value: impliedExit,
    scenarios,
    rationale: `implied_exit = tam_low(${tamLow}) x share(${share}) x exit_multiple(${EXIT_MULTIPLE}) = ${impliedExit}`,
  };
}

// ============================================================================
// §7 -- underestimation guard condition (not itself a §6 scoring term; feeds
// the -0.15 confidence() penalty below). Kept as its own pure function because
// this exact three-condition rule is the one design.md calls out as needing a
// strict evaluation order match -- see the caller contract in confidence().
// ============================================================================

function shadowMarketGuardFires({ ventureScaleStatus, statusQuoIdentified, switchingCost }) {
  // A *measured* FAIL only -- UNKNOWN never fires this (§6.2: "UNKNOWN never
  // triggers §7 either -- a shadow-market hypothesis written on an absent TAM
  // would be fabrication").
  return ventureScaleStatus === 'FAIL' && statusQuoIdentified === true && switchingCost === 1;
}

// ============================================================================
// §5 -- momentum layer
// ============================================================================

const RFC1123_RE =
  /^(?:Mon|Tue|Wed|Thu|Fri|Sat|Sun), (\d{2}) (Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec) (\d{4}) (\d{2}):(\d{2}):(\d{2}) GMT$/;

const RFC1123_MONTHS = Object.freeze({
  Jan: 0, Feb: 1, Mar: 2, Apr: 3, May: 4, Jun: 5,
  Jul: 6, Aug: 7, Sep: 8, Oct: 9, Nov: 10, Dec: 11,
});

// Parses Tavily's actual `results[].published_date` format, verified live
// (§5): "Fri, 26 Jun 2026 06:06:36 GMT" -- RFC 1123, NOT ISO 8601. Anything
// that doesn't match this exact shape (including a well-formed ISO date, or
// no value at all) returns null, i.e. undated -- never `new Date()` / now().
function parseRfc1123Date(value) {
  if (typeof value !== 'string') return null;
  const m = RFC1123_RE.exec(value.trim());
  if (!m) return null;
  const [, dd, mon, yyyy, hh, mi, ss] = m;
  const ms = Date.UTC(Number(yyyy), RFC1123_MONTHS[mon], Number(dd), Number(hh), Number(mi), Number(ss));
  if (Number.isNaN(ms)) return null;
  return new Date(ms);
}

// momentum(newsResults, endDate) -- §5. `endDate` is the pinned run end_date
// (T), NEVER now(), so a re-run of the demo reproduces the same trend. Rule 1
// (thin-signal) is evaluated FIRST and short-circuits rule 2, per design.md's
// explicit ordering note.
function momentum(newsResults, endDate) {
  const t = endDate instanceof Date ? endDate : new Date(endDate);
  if (Number.isNaN(t.getTime())) {
    throw new Error('scoring.js: momentum() requires a valid pinned endDate (the run end_date)');
  }

  const dayMs = 24 * 60 * 60 * 1000;
  const recentStart = new Date(t.getTime() - MOMENTUM_WINDOW.RECENT_DAYS * dayMs); // exclusive lower bound
  const priorStart = new Date(t.getTime() - MOMENTUM_WINDOW.PRIOR_WINDOW_END_DAYS * dayMs); // exclusive lower bound
  const priorEnd = recentStart; // (T-90d), inclusive upper bound for prior -- no gap, no overlap with recent

  let recent = 0;
  let prior = 0;
  let undated = 0;

  for (const result of newsResults || []) {
    const raw = result && result.published_date;
    const parsed = raw ? parseRfc1123Date(raw) : null;
    if (!parsed) {
      undated += 1;
      continue;
    }
    const ms = parsed.getTime();
    if (ms > recentStart.getTime() && ms <= t.getTime()) {
      recent += 1;
    } else if (ms > priorStart.getTime() && ms <= priorEnd.getTime()) {
      prior += 1;
    }
    // else: outside the 180-day window entirely -- not counted in either
    // bucket, and (per §5) not counted as undated either.
  }

  const ratio = recent / Math.max(prior, 1);

  let direction;
  let thinSignal = false;
  if (recent + prior < MOMENTUM_WINDOW.THIN_SIGNAL_MIN_EVENTS) {
    // Rule 1, evaluated first: thin data reads 'stable', regardless of ratio.
    direction = 'stable';
    thinSignal = true;
  } else if (ratio >= MOMENTUM_WINDOW.RATIO_IMPROVING_MIN) {
    direction = 'improving';
  } else if (ratio > MOMENTUM_WINDOW.RATIO_DECLINING_MAX) {
    direction = 'stable';
  } else {
    direction = 'declining';
  }

  return {
    direction,
    recent,
    prior,
    undated,
    ratio,
    thinSignal,
    undatedMajority: undated > recent + prior,
    windowDays: MOMENTUM_WINDOW.PRIOR_WINDOW_END_DAYS,
  };
}

// ============================================================================
// §6.3 -- market axis value
// ============================================================================

function marketScore({ tamBand: tamBandState, cagrBand: cagrBandState, momentum: momentumState, ceiling }) {
  const base = scoreTermFor(MARKET_SCORE_TERMS.tamBand, tamBandState, 'tamBand');
  const cagr = scoreTermFor(MARKET_SCORE_TERMS.cagrBand, cagrBandState, 'cagrBand');
  const mom = scoreTermFor(MARKET_SCORE_TERMS.momentum, momentumState, 'momentum');
  const ceil = scoreTermFor(MARKET_SCORE_TERMS.ceiling, ceiling, 'ceiling');
  return clamp(MARKET_SCORE_RANGE.MIN, MARKET_SCORE_RANGE.MAX, base + cagr + mom + ceil);
}

// market.outlook label (§6.3) -- a claim field, not a scores column. UNKNOWN
// TAM renders 'undetermined', never 'neutral', even though an unresearched
// market's raw value (50) falls in the 'neutral' band -- an unresearched
// market must never render as a confident-looking label.
function marketOutlook(marketScoreValue, tamBandState) {
  if (tamBandState === 'UNKNOWN') return 'undetermined';
  if (marketScoreValue >= MARKET_OUTLOOK_BAND.BULLISH_MIN) return 'bullish';
  if (marketScoreValue >= MARKET_OUTLOOK_BAND.NEUTRAL_MIN) return 'neutral';
  return 'bear';
}

// ============================================================================
// §6.4 -- idea_vs_market axis value
// ============================================================================

function ideaVsMarketScore({ switchingCost = null, threatLevel = null, moat = false, statusQuo = false, zeroCompetitorsNamed = false } = {}) {
  const switchingTerm = scoreTermFor(IDEA_VS_MARKET_TERMS.switchingCost, switchingCost, 'switchingCost');
  const threatTerm = scoreTermFor(IDEA_VS_MARKET_TERMS.threatLevel, threatLevel, 'threatLevel');

  const moatPresent = moat === true;
  // The documented nonlinearity (§6.4): +8, not +10, exactly when
  // threat_level=1 AND switching_cost=1 -- this is what holds the reachable
  // maximum at 100 (50+20+15+8+7) instead of the raw sum's 102. Do not
  // "simplify" this back to a flat +10.
  const atNonlinearCap = moatPresent && threatLevel === 1 && switchingCost === 1;
  const moatTerm = moatPresent
    ? (atNonlinearCap ? IDEA_VS_MARKET_TERMS.moatBonusAtMax : IDEA_VS_MARKET_TERMS.moatBonus)
    : 0;

  const statusQuoTerm = statusQuo === true ? IDEA_VS_MARKET_TERMS.statusQuoDisplacedBonus : 0;

  // zeroCompetitorsNamed: true = the -10 term fires; false OR null (no deck /
  // no founder competition view -- "not assessable") both contribute 0.
  const zeroCompetitorsTerm = zeroCompetitorsNamed === true ? IDEA_VS_MARKET_TERMS.zeroCompetitorsNamedPenalty : 0;

  const sum = IDEA_VS_MARKET_BASE + switchingTerm + threatTerm + moatTerm + statusQuoTerm + zeroCompetitorsTerm;
  return clamp(IDEA_VS_MARKET_RANGE.MIN, IDEA_VS_MARKET_RANGE.MAX, sum);
}

// ============================================================================
// §6.5 -- confidence (+ §7 penalty, applied last)
// ============================================================================

// confidence({ missingCount, evidenceCt, caps, shadowMarketPenalty })
//   caps.noDocumentedTierEvidence   -- no documented-tier evidence behind the size claim
//   caps.fewerThanTwoIndependentDomains
//   caps.topDownOnly
// The evidence_ct=0 cap is derived from evidenceCt itself (not part of
// `caps`) since it is fully determined by the other required argument.
//
// Order (§6.5 + §7, binding): raw formula -> all hard caps (order among caps
// does not matter, each is an independent min()) -> §7's -0.15 penalty last,
// floored at 0.1. Capped-then-penalised can only go lower; the reverse order
// would let a cap silently restore confidence the guard just removed.
function confidence({ missingCount = 0, evidenceCt = 0, caps = {}, shadowMarketPenalty = false } = {}) {
  const cappedMissing = Math.min(Math.max(0, missingCount), CONFIDENCE_FORMULA.MISSING_COUNT_CAP);
  const cappedEvidence = Math.min(Math.max(0, evidenceCt), CONFIDENCE_FORMULA.EVIDENCE_CT_CAP);

  const completeness = 1 - Math.min(1, cappedMissing * CONFIDENCE_FORMULA.MISSING_COUNT_STEP);
  let value =
    (cappedEvidence / CONFIDENCE_FORMULA.EVIDENCE_CT_CAP) * CONFIDENCE_FORMULA.EVIDENCE_WEIGHT +
    completeness * CONFIDENCE_FORMULA.COMPLETENESS_WEIGHT;

  if (evidenceCt === 0) value = Math.min(value, CONFIDENCE_CAPS.ZERO_EVIDENCE);
  if (caps.noDocumentedTierEvidence) value = Math.min(value, CONFIDENCE_CAPS.NO_DOCUMENTED_EVIDENCE);
  if (caps.fewerThanTwoIndependentDomains) value = Math.min(value, CONFIDENCE_CAPS.FEW_INDEPENDENT_DOMAINS);
  if (caps.topDownOnly) value = Math.min(value, CONFIDENCE_CAPS.TOP_DOWN_ONLY);

  if (shadowMarketPenalty) {
    value = Math.max(SHADOW_MARKET_GUARD.CONFIDENCE_FLOOR, value - SHADOW_MARKET_GUARD.CONFIDENCE_PENALTY);
  }

  return clamp(0, 1, value);
}

// ============================================================================
// §3.4 -- evidence tiering by domain, default-deny to 'inferred'
// ============================================================================

function registrableDomain(url) {
  try {
    let host = new URL(url).hostname.toLowerCase();
    if (host.startsWith('www.')) host = host.slice(4);
    return host || null;
  } catch {
    return null;
  }
}

function matchDomainRule(url) {
  const host = registrableDomain(url);
  if (!host) return null;
  for (const rule of DOMAIN_TIER_RULES) {
    if (rule.suffixes && rule.suffixes.some((suffix) => host === suffix.slice(1) || host.endsWith(suffix))) {
      return rule;
    }
    if (rule.domains && rule.domains.some((domain) => host === domain || host.endsWith(`.${domain}`))) {
      return rule;
    }
  }
  return null;
}

// tierForDomain(url) -> 'documented' | 'discovered' | 'inferred'. Default-deny:
// any domain matching no rule -- allow-listed or not, seen before or not --
// is 'inferred' (§3.4). This is the guarantee that makes a brand-new,
// never-seen report mill fail safe without needing to be on the blocklist.
function tierForDomain(url) {
  const rule = matchDomainRule(url);
  return rule ? rule.tier : DEFAULT_DOMAIN_TIER;
}

// evidence.strength for a given URL (§3.4's table has TWO strengths inside
// the 'documented' tier -- 0.90 for government/patents, 0.80 for named
// analyst firms/press -- so this cannot be derived from tierForDomain()'s
// output alone).
function evidenceStrengthForDomain(url) {
  const rule = matchDomainRule(url);
  return rule ? rule.strength : DEFAULT_DOMAIN_STRENGTH;
}

function isBlocklisted(url) {
  const host = registrableDomain(url);
  if (!host) return false;
  return REPORT_MILL_BLOCKLIST.some((domain) => host === domain || host.endsWith(`.${domain}`));
}

// ============================================================================
// §3.5 -- content-hash recipes (idempotency on append-only, NOT NULL UNIQUE
// content_hash columns).
//
// design.md writes each recipe as `sha256(a ‖ b ‖ c)` -- concatenation, with
// no delimiter specified between fields. A delimiter is required here or
// "ab"+"c" and "a"+"bc" collide; NUL (�) is used because it is
// vanishingly unlikely to appear in any of the source fields (URLs, slugs,
// uuids, ISO timestamps). This is an implementation detail design.md leaves
// unspecified, not a deviation from the recipe's field list or order.
// ============================================================================

const HASH_FIELD_DELIMITER = '�';

function sha256Hex(input) {
  return crypto.createHash('sha256').update(input, 'utf8').digest('hex');
}

function hashFields(...parts) {
  return sha256Hex(parts.map((part) => (part === null || part === undefined ? '' : String(part))).join(HASH_FIELD_DELIMITER));
}

const contentHash = {
  // raw_signals: sha256(source ‖ source_url ‖ query ‖ observed_at)
  rawSignal({ source, source_url, query, observed_at }) {
    return hashFields(source, source_url, query, observed_at);
  },
  // claims: sha256(card_id ‖ topic ‖ ai_run_id ‖ item_key) -- item_key is what
  // keeps N-rows-per-run topics (competitors, tailwinds/headwinds) from
  // colliding; ai_run_id is what keeps a re-run's claims as NEW rows so
  // scores.trend has history.
  claim({ card_id, topic, ai_run_id, item_key }) {
    return hashFields(card_id, topic, ai_run_id, item_key);
  },
  // evidence: sha256(claim_id ‖ relation ‖ coalesce(source_url,'') ‖
  // coalesce(quote_verbatim,'') ‖ coalesce(query,'')) -- the `query`
  // discriminator is what keeps multiple tier='missing' rows (NULL url, NULL
  // quote) on one claim from colliding.
  evidence({ claim_id, relation, source_url, quote_verbatim, query }) {
    return hashFields(claim_id, relation, source_url ?? '', quote_verbatim ?? '', query ?? '');
  },
};

// ============================================================================
// §4 -- curator (score >= 0.4 gate, URL-normalised dedup, first-party
// exemption scoped to the relevance gate only, top-8 survivors).
//
// "bucket" (design.md §4's node-chain line: "top-8 per bucket") is not
// further defined in design.md beyond that one mention. This function
// curates ONE array of results (one bucket, e.g. one query's results) down
// to its top CURATE.TOP_N survivors; the caller (the n8n workflow) is
// expected to invoke it once per bucket/query, per the design's Q1-Q5 shape.
// Flagged to the team lead as a judgment call, not a blocking ambiguity.
// ============================================================================

function normalizeUrl(url) {
  try {
    const u = new URL(url);
    let host = u.hostname.toLowerCase();
    if (host.startsWith('www.')) host = host.slice(4);
    let path = u.pathname.toLowerCase();
    if (path.length > 1 && path.endsWith('/')) path = path.slice(0, -1);
    return `${host}${path}`;
  } catch {
    return String(url || '').trim().toLowerCase();
  }
}

function curate(results, companyDomain) {
  const companyHost = companyDomain ? String(companyDomain).toLowerCase().replace(/^www\./, '') : null;

  const survivors = [];
  const indexByNormalizedUrl = new Map();

  for (const result of results || []) {
    if (!result || !result.url) continue;
    // Defense-in-depth: Tavily's exclude_domains is the primary blocklist
    // enforcement, but the curator "is still subject to the blocklist" (§4).
    if (isBlocklisted(result.url)) continue;

    const host = registrableDomain(result.url);
    const isFirstParty = Boolean(companyHost && host && (host === companyHost || host.endsWith(`.${companyHost}`)));
    const score = typeof result.score === 'number' ? result.score : 0;

    // First-party exemption bypasses ONLY the relevance gate -- it is still
    // deduplicated and still subject to the blocklist above (§4).
    if (!isFirstParty && score < CURATE.RELEVANCE_MIN) continue;

    const key = normalizeUrl(result.url);
    const candidate = { ...result, firstParty: isFirstParty };
    const existingIndex = indexByNormalizedUrl.get(key);
    if (existingIndex === undefined) {
      indexByNormalizedUrl.set(key, survivors.length);
      survivors.push(candidate);
    } else if (score > (typeof survivors[existingIndex].score === 'number' ? survivors[existingIndex].score : 0)) {
      survivors[existingIndex] = candidate; // keep the higher-scored duplicate
    }
  }

  survivors.sort((a, b) => (typeof b.score === 'number' ? b.score : 0) - (typeof a.score === 'number' ? a.score : 0));
  return survivors.slice(0, CURATE.TOP_N);
}

